CREATE TABLE "work"."jobs" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "parent_job_id" uuid, "org_id" uuid NOT NULL, "type" text NOT NULL, "data" jsonb NOT NULL, "max_retries" int4 NOT NULL DEFAULT 3, "max_child_failures" integer NOT NULL DEFAULT 3, "result" jsonb NOT NULL, "created_at" timestamptz NOT NULL DEFAULT now(), "started_at" timestamptz NOT NULL, "completed_at" timestamptz NOT NULL, "failed_at" timestamptz NOT NULL, PRIMARY KEY ("id") , FOREIGN KEY ("org_id") REFERENCES "identity"."orgs"("id") ON UPDATE restrict ON DELETE no action);
CREATE EXTENSION IF NOT EXISTS pgcrypto;
